using System;using System.Collections.Generic;using System.Linq.Expressions;using System.Reflection;using UnityEngine.Scripting;namespace RishUI{    [AttributeUsage(AttributeTargets.Method, AllowMultiple = false, Inherited = true)]    public class CustomFactoryAttribute : PreserveAttribute { }        internal delegate T Activator<out T>();    internal static class Activators    {        private static Dictionary<Type, MethodInfo> Methods { get; } = new Dictionary<Type, MethodInfo>();                static Activators()        {            foreach (var asm in AppDomain.CurrentDomain.GetAssemblies())            {                if (Rish.ShouldIgnoreAssembly(asm))                {                    continue;                }                foreach (var type in asm.GetTypes())                {                    var factories = GetFactories(type);                    foreach (var factory in factories)                    {                        var returnType = factory.ReturnType;                        if (Methods.ContainsKey(returnType))                        {                            continue;                        }                        Methods[returnType] = factory;                    }                }            }        }                internal static Activator<T> Get<T>(Type type)        {            var returnType = typeof(T);                        if(type != returnType && !type.IsSubclassOf(typeof(T)))            {                throw new ArgumentException($"{type.FullName} isn't a subtype of {returnType.FullName}");            }            if (Methods.TryGetValue(type, out var factory))            {                return (Activator<T>) Delegate.CreateDelegate(typeof(Activator<T>), null, factory);             }                        var constructorInfo = type.GetConstructor(Type.EmptyTypes);            if (constructorInfo == null)            {                throw new ArgumentException($"No parameterless constructor found for {type.FullName}.");            }                        var expression = Expression.New(constructorInfo);            var lambda = Expression.Lambda(typeof(Activator<T>), expression);            return (Activator<T>) lambda.Compile();        }        private static IEnumerable<MethodInfo> GetFactories(Type type)        {            foreach (var method in type.GetMethods(BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Static))            {                var parameters = method.GetParameters();                if (parameters.Length == 0 && Attribute.IsDefined(method, typeof(CustomFactoryAttribute)))                {                    yield return method;                }            }        }    }}